import{_ as i,o as r,c as s,a2 as t}from"./chunks/framework.Cuq8tsM6.js";const m=JSON.parse('{"title":"Compte & Audiences","description":"","frontmatter":{"title":"Compte & Audiences"},"headers":[],"relativePath":"docs/fr/faq/account-audiences.md","filePath":"docs/fr/faq/account-audiences.md"}'),o={name:"docs/fr/faq/account-audiences.md"};function a(d,e,n,u,p,l){return r(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="compte-equipe-audiences" tabindex="-1">Compte, Équipe &amp; Audiences <a class="header-anchor" href="#compte-equipe-audiences" aria-label="Permalink to &quot;Compte, Équipe &amp; Audiences&quot;">​</a></h1><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment ajouter un nouvel utilisateur ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Rendez-vous dans <strong>Mon Organisation &gt; Équipe</strong> et cliquez sur <code>+ Ajouter un membre</code>. Nous recommandons d&#39;avoir toujours au moins un backup pour assurer la réactivité. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment référencer une nouvelle audience ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Allez dans <strong>Monétisation &gt; Catalogue</strong> et cliquez sur <code>+ Nouvelle audience</code>. Remplissez les fiches avec soin (Marque, Persona, Panier Moyen) car ce sont ces infos qui convaincront les annonceurs. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Faut-il créer plusieurs comptes si j&#39;ai plusieurs sites ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Non. Vous pouvez gérer autant d’audiences que vous le souhaitez depuis un seul compte getinside. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">getinside est-il présent à l&#39;international ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Oui, nous monétisons des audiences dans toute l’Europe. Vous pouvez ajouter vos audiences européennes et recevoir des campagnes pour ces pays. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Comment suivre mes marques affiliées ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Le statut de vos filleuls est visible dans l&#39;onglet <strong>Affiliation</strong>. Dès qu&#39;ils s&#39;activent, vos commissions apparaissent automatiquement dans <strong>Transactions &gt; Revenus</strong>. </div></details><details style="margin-bottom:10px;border:1px solid var(--vp-c-divider);border-radius:6px;padding:15px;"><summary style="font-weight:bold;cursor:pointer;">Pourquoi mon &quot;Score Distributeur&quot; a baissé ?</summary><div style="margin-top:10px;padding-left:20px;border-left:1px solid var(--vp-c-divider);"> Le score est recalculé dynamiquement. Une baisse peut être due à : <ul><li>Un délai de réponse trop long (&gt; 48h) sur vos dernières demandes.</li><li>Des refus de propositions de campagne sans contre-proposition ni justification.</li><li>Des délais de distribution plus long que prévus (Fiabilité).</li><li>Un tarif CPM jugé trop élevé par rapport à la concurrence de votre secteur.</li></ul> Contactez l&#39;équipe getinside pour voir quel axe améliorer. </div></details>',7)])])}const v=i(o,[["render",a]]);export{m as __pageData,v as default};
